from pathlib import Path

from supportmind.evaluation.runner import run_evaluation

RESULTS_PATH = Path("results/ragas.md")


if __name__ == "__main__":
    results = run_evaluation()
    table = results.to_markdown(index=False)
    print(table)

    RESULTS_PATH.parent.mkdir(parents=True, exist_ok=True)
    RESULTS_PATH.write_text(
        "# RAGAS Retrieval Evaluation\n\n"
        "Generated by `scripts/run_evaluation.py` against the Bitext sample evaluation set "
        "(`config.evaluation.sample_size` rows, seeded for reproducibility).\n\n"
        f"{table}\n"
        "\nMetrics: faithfulness, answer_relevance, context_precision, context_recall (RAGAS), "
        "plus average end-to-end latency per variant.\n",
        encoding="utf-8",
    )
    print(f"\nResults written to {RESULTS_PATH}")
